+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[]; exclusive: boolean }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] };
+
+export type Deferred = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, ...traits: RelationPair[]): void;
+    flush(): void;
+};
+
+type DeferredState = { buffers: Command[][]; flushing: boolean };
+
+export function createDeferred(world: World): Deferred {
+    const state: DeferredState = { buffers: [[]], flushing: false };
+    world[$internal].deferredState = state;
+    const current = () => state.buffers[state.buffers.length - 1];
+    return {
+        spawn(...traits) {
+            // Reserve a stable numeric entity now; traits remain invisible to queries until flush.
+            const entity = createEntity(world);
+            current().push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current().push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current().push({ type: 'add', entity, traits, exclusive: false }); },
+        remove(entity, ...traits) { current().push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) { current().push({ type: 'add', entity, traits, exclusive: true }); },
+        flush() { flushDeferred(world, state); },
+    };
+}
+
+export function beginDeferredScope(world: World) {
+    const state = world[$internal].deferredState as DeferredState | undefined;
+    if (state) state.buffers.push([]);
+}
+
+export function endDeferredScope(world: World) {
+    const state = world[$internal].deferredState as DeferredState | undefined;
+    if (!state) return;
+    const commands = state.buffers.pop()!;
+    execute(world, state, commands);
+}
+
+export function flushEntityDeferred(world: World, entity: Entity) {
+    const state = world[$internal].deferredState as DeferredState | undefined;
+    if (!state || state.flushing || !state.buffers.some((b) => b.some((c) => c.entity === entity))) return;
+    // A non-deferred write is an ordering boundary for this entity.
+    for (const buffer of state.buffers) {
+        const mine = buffer.filter((c) => c.entity === entity);
+        if (mine.length) {
+            for (const command of mine) buffer.splice(buffer.indexOf(command), 1);
+            execute(world, state, mine);
+        }
+    }
+}
