+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const state = world[$internal].deferredState as DeferredState | undefined;
+    if (!state || state.flushing) return undefined;
+    let value = isRelationPair(trait) ? hasRelationPair(world, entity, trait) : hasTrait(world, entity, trait);
+    let touched = false;
+    for (const command of state.buffers.flat()) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') return false;
+        if (command.type === 'spawn') { touched = true; continue; }
+        for (const config of command.traits) {
+            const matches = sameTrait(config, trait);
+            if (!matches) continue;
+            touched = true;
+            if (command.type === 'remove') value = false;
+            else if (command.exclusive && isRelationPair(config) && isRelationPair(trait) && trait[$internal].target === '*') value = false;
