+function execute(world: World, state: DeferredState, commands: Command[]) {
+    if (!commands.length) return;
+    state.flushing = true;
+    try {
+        const spawned = new Set(commands.filter((c): c is Extract<Command, { type: 'spawn' }> => c.type === 'spawn').map((c) => c.entity));
+        const cancelled = new Set(commands.filter((c) => c.type === 'destroy' && spawned.has(c.entity)).map((c) => c.entity));
